import json

filepath = "/Users/anotonio.silva/.claude/projects/-Users-anotonio-silva-antonio-mms-system/34c1e0bd-3e55-46d7-a3d5-49f42992897f.jsonl"

with open(filepath, 'r') as f:
    lines = f.readlines()

# Extract commits and major actions
start_idx = max(0, len(lines) - 500)
commits = []
edits = []
todos = []

for i, line in enumerate(lines[start_idx:], start=start_idx):
    try:
        data = json.loads(line)

        # Look for git commits in messages
        if 'message' in data:
            msg = data['message']
            if isinstance(msg, dict):
                for item in msg.get('content', []):
                    if isinstance(item, dict):
                        # Check tool_use for Bash (git commands)
                        if item.get('type') == 'tool_use' and item.get('name') == 'Bash':
                            cmd = item.get('input', {}).get('command', '')
                            if 'git commit' in cmd or 'git push' in cmd:
                                commits.append((i, cmd[:200]))

                        # Check for Edit tools
                        elif item.get('type') == 'tool_use' and item.get('name') == 'Edit':
                            edit_info = item.get('input', {})
                            path = edit_info.get('file_path', 'unknown')[:80]
                            edits.append((i, path))

                        # Check TodoWrite
                        elif item.get('type') == 'tool_use' and item.get('name') == 'TodoWrite':
                            todos.append(i)

                        # Look for text containing "commit"
                        elif item.get('type') == 'text':
                            text = item.get('text', '')
                            if 'commit' in text.lower():
                                commits.append((i, text[:150]))

    except json.JSONDecodeError:
        continue

print("=" * 70)
print("COMMITS MADE")
print("=" * 70)
for idx, commit_msg in commits[-15:]:
    print(f"Line {idx}: {commit_msg}")

print("\n" + "=" * 70)
print("FILE EDITS (last 15)")
print("=" * 70)
edited_files = {}
for idx, path in edits[-30:]:
    if path not in edited_files:
        edited_files[path] = []
    edited_files[path].append(idx)

for path, line_nums in sorted(edited_files.items(), key=lambda x: -len(x[1]))[:15]:
    print(f"{path}: {len(line_nums)} edit(s)")

print("\n" + "=" * 70)
print("TODO UPDATES")
print("=" * 70)
print(f"TodoWrite used {len(todos)} times at lines: {todos}")

